//! Per-layer residual capture sink for the Pleromatic Residual Atlas.
//!
//! Env-gated: set `GNOSIS_RESIDUAL_CAPTURE=/path/to/dir` to enable.
//! When unset, the global sink is a no-op `NullResidualSink` and there
//! is zero cost on the inference hot path.
//!
//! **Track A mesh spectrometer** (optional, native only): set
//! `GNOSIS_MESH_SPECTROMETER_JSONL=/path/to/file.jsonl` to append one
//! `gnosis.mesh-spectrometer.v1` JSON line per [`capture_residual`] call
//! (in addition to any BWMR sink). Optional `GNOSIS_SPECTROMETER_EXPERIMENT_ID`
//! defaults to `residual-pid{pid}` for correlating with knot-shadow sidecars.
//! **Auto-export (native):** truthy `GNOSIS_MESH_AUTO_CAPTURE_BATCH_X_EXPORT` hooks
//! `get_batch_x_residual` / Gemma `get_residual` → [`maybe_capture_on_batch_x_export`].
//! Layer defaults to [`CAPTURE_LAYER_UNKNOWN`] (`u16::MAX`, omitted in mesh JSON); sequence uses a
//! process-wide ascending counter.
//! **Pair X** / **amplituhedron replay** on each row: env
//! `GNOSIS_MESH_SPECTROMETER_PAIR_X_SEEDED`, `GNOSIS_MESH_SPECTROMETER_AMPLITUHEDRON_REPLAY_HIT`,
//! [`install_spectrometer_lane_flags`], and (after a Death #2 cache hit)
//! [`hint_amplituhedron_replay_hit`] sticky until the next spectrometer JSONL append.
//! See `TOPOLOGICAL_SPECTROMETER_DUAL_TRACK.md`.
//!
//! Wire format (BWMR — Bitwise Residual): one file per process,
//! append-only; record = u16 layer_idx | u32 seq_idx | u32 hidden_dim
//! | u64 capture_timestamp_ms | f32[hidden_dim] (little-endian).

#![allow(dead_code)]

use std::fs::{File, OpenOptions};
use std::io::{BufWriter, Write};
use std::path::{Path, PathBuf};
use std::sync::Mutex;
use std::sync::OnceLock;

#[cfg(not(target_arch = "wasm32"))]
use std::sync::atomic::{AtomicU32, Ordering};

#[cfg(not(target_arch = "wasm32"))]
static MESH_SPECTROMETER_JSONL: OnceLock<Option<PathBuf>> = OnceLock::new();

#[cfg(not(target_arch = "wasm32"))]
static MESH_SPECTROMETER_EXPERIMENT_ID: OnceLock<String> = OnceLock::new();

pub use crate::spectrometer::SpectrometerLaneFlags;
#[cfg(not(target_arch = "wasm32"))]
pub use crate::spectrometer::{
    hint_amplituhedron_replay_hit, install_spectrometer_lane_flags,
    spectrometer_lane_flags_effective,
};

/// `layer_idx` when the exporting path does not know the mesh layer. Stored as `65535` in BWMR;
/// mesh JSONL omits `layer_idx`.
pub const CAPTURE_LAYER_UNKNOWN: u16 = u16::MAX;

#[cfg(not(target_arch = "wasm32"))]
static MESH_AUTO_CAPTURE_BATCH_X_EXPORT: OnceLock<bool> = OnceLock::new();

#[cfg(not(target_arch = "wasm32"))]
static MESH_CAPTURE_EXPORT_LAYER_IDX: OnceLock<u16> = OnceLock::new();

#[cfg(not(target_arch = "wasm32"))]
static EXPORT_CAPTURE_SEQ: AtomicU32 = AtomicU32::new(0);

pub struct ResidualCapture {
    pub layer_idx: u16,
    pub seq_idx: u32,
    pub hidden_dim: u32,
    pub capture_timestamp_ms: u64,
    pub values: Vec<f32>,
}

pub trait ResidualSink: Send + Sync {
    fn capture(&self, c: &ResidualCapture);
    fn flush(&self);
}

/// Default no-op sink. Zero cost.
pub struct NullResidualSink;

impl ResidualSink for NullResidualSink {
    fn capture(&self, _c: &ResidualCapture) {}
    fn flush(&self) {}
}

/// File-backed sink: appends BWMR records to a single file.
pub struct FileResidualSink {
    writer: Mutex<BufWriter<File>>,
}

impl FileResidualSink {
    pub fn open(path: &Path) -> std::io::Result<Self> {
        let file = OpenOptions::new().create(true).append(true).open(path)?;
        Ok(Self {
            writer: Mutex::new(BufWriter::new(file)),
        })
    }
}

impl ResidualSink for FileResidualSink {
    fn capture(&self, c: &ResidualCapture) {
        if let Ok(mut w) = self.writer.lock() {
            // BWMR record: u16 layer + u32 seq + u32 hidden_dim + u64 ts + f32[hidden_dim]
            let _ = w.write_all(&c.layer_idx.to_le_bytes());
            let _ = w.write_all(&c.seq_idx.to_le_bytes());
            let _ = w.write_all(&c.hidden_dim.to_le_bytes());
            let _ = w.write_all(&c.capture_timestamp_ms.to_le_bytes());
            let bytes: &[u8] = bytemuck::cast_slice(&c.values);
            let _ = w.write_all(bytes);
        }
    }
    fn flush(&self) {
        if let Ok(mut w) = self.writer.lock() {
            let _ = w.flush();
        }
    }
}

/// Global sink. Default = NullResidualSink. Override via env at startup.
static GLOBAL_SINK: OnceLock<Box<dyn ResidualSink>> = OnceLock::new();

pub fn install_global_sink(sink: Box<dyn ResidualSink>) {
    let _ = GLOBAL_SINK.set(sink);
}

pub fn global_sink() -> &'static dyn ResidualSink {
    GLOBAL_SINK
        .get_or_init(|| {
            // Probe env once.
            if let Ok(dir) = std::env::var("GNOSIS_RESIDUAL_CAPTURE") {
                let pid = std::process::id();
                let path = PathBuf::from(dir).join(format!("capture-{}.bwmr", pid));
                if let Some(parent) = path.parent() {
                    let _ = std::fs::create_dir_all(parent);
                }
                match FileResidualSink::open(&path) {
                    Ok(s) => Box::new(s),
                    Err(_) => Box::new(NullResidualSink),
                }
            } else {
                Box::new(NullResidualSink)
            }
        })
        .as_ref()
}

/// Convenience: capture a residual at the given layer/seq.
pub fn capture_residual(layer_idx: u16, seq_idx: u32, values: &[f32]) {
    let c = ResidualCapture {
        layer_idx,
        seq_idx,
        hidden_dim: values.len() as u32,
        capture_timestamp_ms: now_ms(),
        values: values.to_vec(),
    };
    global_sink().capture(&c);

    #[cfg(not(target_arch = "wasm32"))]
    let _ = try_append_mesh_spectrometer_row_for_residual(
        mesh_spectrometer_jsonl_path(),
        None,
        &c,
        values,
        None,
    );
}

/// Like [`capture_residual`], with an optional per-row spectrometer lane overlay (merged after env / install, before consumed replay hint). Native-only (mesh spectrometer rows are not written on wasm).
#[cfg(not(target_arch = "wasm32"))]
pub fn capture_residual_with_row_lane_overlay(
    layer_idx: u16,
    seq_idx: u32,
    values: &[f32],
    row_lane: Option<SpectrometerLaneFlags>,
) {
    let c = ResidualCapture {
        layer_idx,
        seq_idx,
        hidden_dim: values.len() as u32,
        capture_timestamp_ms: now_ms(),
        values: values.to_vec(),
    };
    global_sink().capture(&c);

    let _ = try_append_mesh_spectrometer_row_for_residual(
        mesh_spectrometer_jsonl_path(),
        None,
        &c,
        values,
        row_lane,
    );
}

/// When `GNOSIS_MESH_AUTO_CAPTURE_BATCH_X_EXPORT` is truthy, calls [`capture_residual`]
/// using [`CAPTURE_LAYER_UNKNOWN`] unless `GNOSIS_MESH_CAPTURE_LAYER_IDX` is set, and a monotonic `seq`.
#[cfg(not(target_arch = "wasm32"))]
pub fn maybe_capture_on_batch_x_export(values: &[f32], seq_len_tokens: usize, hidden_dim: usize) {
    if !mesh_auto_capture_batch_x_export_enabled() {
        return;
    }
    let n = seq_len_tokens.saturating_mul(hidden_dim);
    if n == 0 || values.len() != n {
        return;
    }
    let layer = mesh_capture_export_layer_idx();
    let seq = EXPORT_CAPTURE_SEQ.fetch_add(1, Ordering::Relaxed);
    capture_residual(layer, seq, values);
}

/// Append one [`crate::spectrometer::SpectrometerMeshRow`] when `jsonl_path` is `Some`.
/// `experiment_id = None` uses `GNOSIS_SPECTROMETER_EXPERIMENT_ID` or `residual-pid{pid}`.
#[cfg(not(target_arch = "wasm32"))]
pub fn try_append_mesh_spectrometer_row_for_residual(
    jsonl_path: Option<&Path>,
    experiment_id: Option<&str>,
    c: &ResidualCapture,
    values: &[f32],
    row_lane_overlay: Option<SpectrometerLaneFlags>,
) -> std::io::Result<()> {
    let Some(path) = jsonl_path else {
        return Ok(());
    };
    let exp = experiment_id
        .map(str::to_owned)
        .unwrap_or_else(|| mesh_spectrometer_experiment_id().to_owned());
    let l2: f64 = values
        .iter()
        .map(|x| {
            let d = *x as f64;
            d * d
        })
        .sum();
    let eff = crate::spectrometer::spectrometer_lane_flags_effective();
    let overlay = row_lane_overlay.unwrap_or_default();
    let taken = crate::spectrometer::take_amplituhedron_replay_hint_overlay();
    let lane = eff.overlay(overlay).overlay(taken);
    let row = crate::spectrometer::SpectrometerMeshRow {
        schema_version: crate::spectrometer::MESH_SCHEMA_VERSION.to_owned(),
        experiment_id: exp,
        wall_clock_ms_unix: Some(u128::from(c.capture_timestamp_ms)),
        layer_idx: (c.layer_idx != CAPTURE_LAYER_UNKNOWN).then_some(u32::from(c.layer_idx)),
        residual_capture_seq: Some(c.seq_idx),
        residual_l2_sum_sq: Some(l2),
        pair_x_seeded: lane.pair_x_seeded,
        amplituhedron_replay_hit: lane.amplituhedron_replay_hit,
    };
    crate::spectrometer::append_mesh_spectrometer_jsonl(path, &row)
}

#[cfg(not(target_arch = "wasm32"))]
fn mesh_spectrometer_jsonl_path() -> Option<&'static Path> {
    MESH_SPECTROMETER_JSONL
        .get_or_init(|| {
            std::env::var_os("GNOSIS_MESH_SPECTROMETER_JSONL")
                .map(PathBuf::from)
                .filter(|p| !p.as_os_str().is_empty())
        })
        .as_deref()
}

#[cfg(not(target_arch = "wasm32"))]
fn mesh_spectrometer_experiment_id() -> &'static str {
    MESH_SPECTROMETER_EXPERIMENT_ID
        .get_or_init(|| {
            std::env::var("GNOSIS_SPECTROMETER_EXPERIMENT_ID")
                .unwrap_or_else(|_| format!("residual-pid{}", std::process::id()))
        })
        .as_str()
}

#[cfg(not(target_arch = "wasm32"))]
fn mesh_auto_capture_batch_x_export_enabled() -> bool {
    *MESH_AUTO_CAPTURE_BATCH_X_EXPORT
        .get_or_init(|| parse_mesh_env_truthy("GNOSIS_MESH_AUTO_CAPTURE_BATCH_X_EXPORT"))
}

#[cfg(not(target_arch = "wasm32"))]
fn mesh_capture_export_layer_idx() -> u16 {
    *MESH_CAPTURE_EXPORT_LAYER_IDX.get_or_init(|| {
        std::env::var("GNOSIS_MESH_CAPTURE_LAYER_IDX")
            .ok()
            .and_then(|s| s.trim().parse().ok())
            .unwrap_or(CAPTURE_LAYER_UNKNOWN)
    })
}

#[cfg(not(target_arch = "wasm32"))]
fn parse_mesh_env_truthy(key: &str) -> bool {
    std::env::var_os(key).is_some_and(|v| {
        let s = v.to_string_lossy();
        matches!(
            s.trim().to_ascii_lowercase().as_str(),
            "1" | "true" | "yes" | "on"
        )
    })
}

fn now_ms() -> u64 {
    use std::time::{SystemTime, UNIX_EPOCH};
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_millis() as u64)
        .unwrap_or(0)
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;
    use std::io::Read;
    use std::sync::atomic::{AtomicU64, Ordering};

    // Monotonic counter to make per-test temp file names unique without
    // depending on `tempfile` (not in Cargo.toml).
    static TEST_COUNTER: AtomicU64 = AtomicU64::new(0);

    fn unique_temp_path(label: &str) -> PathBuf {
        let n = TEST_COUNTER.fetch_add(1, Ordering::SeqCst);
        let pid = std::process::id();
        let ts = now_ms();
        std::env::temp_dir().join(format!(
            "gnosis-residual-capture-{}-{}-{}-{}.bwmr",
            label, pid, ts, n
        ))
    }

    /// Test 1: `NullResidualSink::capture` returns without side effects
    /// and `flush` is also a no-op. Smoke check for zero-cost path.
    #[test]
    fn null_sink_zero_cost() {
        let sink = NullResidualSink;
        let c = ResidualCapture {
            layer_idx: 7,
            seq_idx: 13,
            hidden_dim: 4,
            capture_timestamp_ms: 42,
            values: vec![1.0, 2.0, 3.0, 4.0],
        };
        sink.capture(&c);
        sink.flush();
        // No assertion: success = no panic, no I/O. Compiles == zero observable cost.
    }

    /// Test 2: write one record through `FileResidualSink`, flush by drop,
    /// read raw bytes back and assert the BWMR byte layout matches exactly.
    #[test]
    fn file_sink_writes_record() {
        let path = unique_temp_path("write-record");
        let hidden_dim: u32 = 3;
        let values: Vec<f32> = vec![1.5_f32, -2.25_f32, 0.0_f32];
        let c = ResidualCapture {
            layer_idx: 9u16,
            seq_idx: 17u32,
            hidden_dim,
            capture_timestamp_ms: 0x0123_4567_89AB_CDEFu64,
            values: values.clone(),
        };

        {
            let sink = FileResidualSink::open(&path).expect("open temp");
            sink.capture(&c);
            sink.flush();
            // Drop sink -> BufWriter flushes on drop.
        }

        let mut buf = Vec::new();
        let mut f = File::open(&path).expect("reopen temp");
        f.read_to_end(&mut buf).expect("read temp");

        // Expected layout: 2 + 4 + 4 + 8 + 4*hidden_dim bytes.
        let expected_len = 2 + 4 + 4 + 8 + 4 * hidden_dim as usize;
        assert_eq!(buf.len(), expected_len, "BWMR record length mismatch");

        // Field-by-field little-endian decode.
        assert_eq!(&buf[0..2], &9u16.to_le_bytes());
        assert_eq!(&buf[2..6], &17u32.to_le_bytes());
        assert_eq!(&buf[6..10], &3u32.to_le_bytes());
        assert_eq!(&buf[10..18], &0x0123_4567_89AB_CDEFu64.to_le_bytes());

        assert_eq!(hidden_dim as usize * 4, buf.len() - 18);
        let mut payload = Vec::with_capacity(hidden_dim as usize);
        for i in 0..hidden_dim as usize {
            let off = 18 + i * 4;
            let chunk: [u8; 4] = buf[off..off + 4].try_into().expect("f32 chunk");
            payload.push(f32::from_le_bytes(chunk));
        }
        assert_eq!(payload, values);

        let _ = fs::remove_file(&path);
    }

    /// Test 3: with `GNOSIS_RESIDUAL_CAPTURE` unset at process start,
    /// the global sink must default to `NullResidualSink` and writing
    /// to it must not create any file on disk.
    ///
    /// ORDERING NOTE: `GLOBAL_SINK` is a process-wide `OnceLock`. Rust's
    /// default test harness runs tests in parallel within a single process,
    /// so this test cannot reliably mutate `GNOSIS_RESIDUAL_CAPTURE` after
    /// `global_sink()` has been called by another test. We rely on the
    /// fact that no other test in this module calls `global_sink()`. If
    /// future tests do, mark this test `#[ignore]` and run it under
    /// `cargo test -- --ignored --test-threads=1`.
    #[test]
    fn global_sink_defaults_to_null_when_env_unset() {
        // SAFETY: env mutation is process-global. Safe here because this
        // is the only test in this module that probes the env var, and
        // we restore (remove) it before any other code observes it.
        std::env::remove_var("GNOSIS_RESIDUAL_CAPTURE");

        let sink = global_sink();
        let c = ResidualCapture {
            layer_idx: 0,
            seq_idx: 0,
            hidden_dim: 2,
            capture_timestamp_ms: 1,
            values: vec![0.0, 0.0],
        };
        sink.capture(&c);
        sink.flush();

        // No file path to check directly because Null sink never opens one.
        // The contract is: no panic, no I/O. If the env var had leaked in
        // we'd at least see a file under the dir it pointed to; we assert
        // that env var is unset at this point.
        assert!(std::env::var("GNOSIS_RESIDUAL_CAPTURE").is_err());
    }

    /// Test 4: record length math: 18 + 4*N for hidden_dim = N. Sweep a
    /// few N to be sure the writer doesn't add padding or framing bytes.
    #[test]
    fn bwmr_record_length() {
        for &n in &[0usize, 1, 4, 16, 128, 1024] {
            let path = unique_temp_path(&format!("len-{}", n));
            let values: Vec<f32> = vec![0.0_f32; n];
            let c = ResidualCapture {
                layer_idx: 0,
                seq_idx: 0,
                hidden_dim: n as u32,
                capture_timestamp_ms: 0,
                values,
            };
            {
                let sink = FileResidualSink::open(&path).expect("open temp");
                sink.capture(&c);
                sink.flush();
            }
            let meta = fs::metadata(&path).expect("stat temp");
            let expected = 18u64 + 4u64 * n as u64;
            assert_eq!(
                meta.len(),
                expected,
                "hidden_dim={} expected {} bytes, got {}",
                n,
                expected,
                meta.len()
            );
            let _ = fs::remove_file(&path);
        }
    }

    #[cfg(not(target_arch = "wasm32"))]
    #[test]
    fn mesh_spectrometer_helper_appends_valid_jsonl() {
        let path = unique_temp_path("mesh").with_extension("jsonl");
        let values = vec![2.0_f32, 3.0_f32];
        let c = ResidualCapture {
            layer_idx: 3,
            seq_idx: 9,
            hidden_dim: values.len() as u32,
            capture_timestamp_ms: 99,
            values: values.clone(),
        };
        try_append_mesh_spectrometer_row_for_residual(
            Some(path.as_path()),
            Some("bench-test-exp"),
            &c,
            &values,
            None,
        )
        .expect("append");
        let s = fs::read_to_string(&path).expect("read");
        let mut lines = s.lines();
        let line = lines.next().expect("one line");
        let row: crate::spectrometer::SpectrometerMeshRow =
            serde_json::from_str(line).expect("json");
        assert_eq!(row.schema_version, crate::spectrometer::MESH_SCHEMA_VERSION);
        assert_eq!(row.experiment_id, "bench-test-exp");
        assert_eq!(row.wall_clock_ms_unix, Some(99));
        assert_eq!(row.layer_idx, Some(3));
        assert_eq!(row.residual_capture_seq, Some(9));
        assert!((row.residual_l2_sum_sq.unwrap() - 13.0_f64).abs() < 1e-9);
        assert!(row.pair_x_seeded.is_none());
        assert!(row.amplituhedron_replay_hit.is_none());

        struct ClearLaneFlags;
        impl Drop for ClearLaneFlags {
            fn drop(&mut self) {
                crate::spectrometer::install_spectrometer_lane_flags(None);
            }
        }
        let _clear = ClearLaneFlags;
        crate::spectrometer::install_spectrometer_lane_flags(Some(
            crate::spectrometer::SpectrometerLaneFlags {
                pair_x_seeded: Some(true),
                amplituhedron_replay_hit: Some(false),
            },
        ));
        try_append_mesh_spectrometer_row_for_residual(
            Some(path.as_path()),
            Some("bench-test-exp"),
            &c,
            &values,
            None,
        )
        .expect("append-second");
        let s2 = fs::read_to_string(&path).expect("read-after");
        let line2 = s2.lines().nth(1).expect("second line");
        let row2: crate::spectrometer::SpectrometerMeshRow =
            serde_json::from_str(line2).expect("json2");
        assert_eq!(row2.pair_x_seeded, Some(true));
        assert_eq!(row2.amplituhedron_replay_hit, Some(false));

        let _ = fs::remove_file(&path);
    }

    #[cfg(not(target_arch = "wasm32"))]
    #[test]
    fn mesh_jsonl_omits_unknown_layer_idx() {
        let path = unique_temp_path("mesh-un").with_extension("jsonl");
        let values = vec![1.0_f32];
        let c = ResidualCapture {
            layer_idx: CAPTURE_LAYER_UNKNOWN,
            seq_idx: 1,
            hidden_dim: 1,
            capture_timestamp_ms: 0,
            values: values.clone(),
        };
        try_append_mesh_spectrometer_row_for_residual(
            Some(path.as_path()),
            Some("un-layer"),
            &c,
            &values,
            None,
        )
        .expect("append");
        let row: crate::spectrometer::SpectrometerMeshRow = serde_json::from_str(
            fs::read_to_string(&path)
                .expect("r")
                .lines()
                .next()
                .unwrap(),
        )
        .expect("json");
        assert!(row.layer_idx.is_none());
        let _ = fs::remove_file(&path);
    }
}
